def min_max_scale(arr):
    mn = min(arr)
    mx = max(arr)
    if mx == mn:
        return [0 for _ in arr]
    return [(x - mn) / (mx - mn) for x in arr]

def filter_non_empty(strings):
    result = []
    for s in strings:
        cleaned = s.strip()
        if cleaned:
            result.append(cleaned)
    return result
